INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 8614, 1, 11, "私たちはみんな、同じ食卓を囲む\n家族なんだから。\n大事な家族の特別な日を\nお祝いするのは、当然のことよ。", 0, 8614066, 0, 10, 1, 106411);
