INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 11514, 1, 11, "覚えていてくれただけでうれしいのに、\nこんなに豪華な用意までしてもらって……", 0, 11514073, 0, 10, 1, 102111);
