INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 14714, "", 3, "wac_birthday_talk_doya", "", 14714071, 0.2, 1, "", 100911);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 14714, "", 21, "vo_wac_14714_001", "", 14714072, "", 0, 0, "vo_wac_14714");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 14714, 1, 11, "ふっ、ルカには日ごろ世話になってる\nからな！　生誕を祝うのは当然だ！\nちなみに私はローソクを立てたぞ！\n見ろ、完璧なバランスだろう！？", 0, 14714073, 0, 10, 1, 100911);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 14714, "", 91, "", "", 14714074, "", "", "", 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 14714, "", 3, "wac_birthday_idle_doya", "", 14714075, 0.2, 1, "", 100911);
