INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 14714, "", 21, "vo_wac_14714_003", "", 14714081, "", 0, 0, "vo_wac_14714");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 14714, 1, 11, "そら、アンタたちも食べな。\nせっかく用意してくれた\nごちそうなんだ。みんなで\n景気よく楽しもうじゃないか♪", 0, 14714082, 0, 10, 1, 105611);
