INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 18814, 1, 11, "こ、ここ、これはまさか～！？\nナナカちゃん生誕祭の準備！？\n……であってるよね？　単にケーキを\n食べたかっただけとかじゃないよね？", 0, 18814071, 0, 10, 1, 101311);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 18814, "", 91, "", "", 18814072, "", "", "", 0);
