INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 18814, "", 3, "wac_birthday_talk_doya", "", 18814074, 0.2, 1, "", 105611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 18814, "", 21, "vo_wac_18814_001", "", 18814075, "", 0, 0, "vo_wac_18814");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 18814, 1, 11, "どう見たって誕生日ケーキだろう？\n心配しなくても、ナナカのお祝いだ。\n誕生日、おめでとう。", 0, 18814076, 0, 10, 1, 105611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 18814, "", 91, "", "", 18814077, "", "", "", 0);
