INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 18814, 1, 11, "ところで。\nどうしてナナカさんが欲しがっている\n限定品を、あなた様が正確に把握して\nいらっしゃったのでしょう……？", 0, 18814096, 0, 10, 1, 102711);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 18814, "", 91, "", "", 18814097, "", "", "", 0);
