INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 18814, 1, 11, "それは～、えーっと……\nやばい、目が笑ってないでござる。\n定期巡回のことを話したら、\n確実に斧でケーキ入刀される～！？", 0, 18814101, 0, 10, 1, 101311);
