INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 19814, 1, 11, "誕生日にそんなことされて喜ぶのは、\nクウカさんだけだと思います……", 0, 19814086, 0, 10, 1, 105511);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 19814, "", 91, "", "", 19814087, "", "", "", 0);
