INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 19814, 1, 11, "ちなみに、このケーキは美しいボクと\nギルドの仲間たち、それといつもの\nこの人で選んだんだ。主にボクの\n顔を思い浮かべつつ味わってよね♪", 0, 19814096, 0, 10, 1, 100811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 19814, "", 91, "", "", 19814097, "", "", "", 0);
