INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 20014, 1, 11, "もちろん、キャルさまのでございます。\n【美食殿】全員で心を込めて\nご用意させていただいた、特製の\n手作りケーキとなっております。", 0, 20014080, 0, 10, 1, 105911);
