INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 20014, 1, 11, "そっか……えへへ……♪\nなら、最初っからそう言いなさいよ。\nそしたら素直にお礼だって言えるし。\n……うん、ありがとう♪", 0, 20014085, 0, 10, 1, 106011);
