INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 22014, 1, 11, "我らがギルドマスターの誕生日だ。\n派手に奮発して、盛大に祝って\nやらないとな♪\nどんどん盛り上げていこうぜ！", 0, 22014068, 0, 10, 1, 104311);
