INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 22714, 1, 11, "年に一度のイノリ様の誕生日が\nきやがったですよ！\nファミリー総出で景気よく、これ以上\nないほど盛大にお祝いしやがれです！", 0, 22714056, 0, 10, 1, 106611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 22714, "", 91, "", "", 22714057, "", "", "", 0);
