INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 22714, "", 21, "vo_wac_22714_001", "", 22714060, "", 0, 0, "vo_wac_22714");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 22714, 1, 11, "……イノリちゃん？\nみんなイノリちゃんのためにケーキを\n用意して集まってくれてるんだから、\nまずはなんて言うのが正しいのかな～？", 0, 22714061, 0, 10, 1, 106711);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 22714, "", 91, "", "", 22714062, "", "", "", 0);
