INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 22714, "", 3, "wac_birthday_talk_sad", "", 22714064, 0.2, 1, "", 106611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 22714, "", 21, "vo_wac_22714_002", "", 22714065, "", 0, 0, "vo_wac_22714");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 22714, 1, 11, "えっ、あっ、それは……！？\nここ、この度はあたしのお誕生日を\nお祝いしてくれやがりまして、まことに\nありがとうございますです！", 0, 22714066, 0, 10, 1, 106611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 22714, "", 91, "", "", 22714067, "", "", "", 0);
