INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 22714, 1, 11, "いや、どんな敬語だよ……\nでも、気持ちは伝わったかな？\nケーキ一つでこんなにご機嫌なんだ、\n来年もまた、用意してやりますか。", 0, 22714071, 0, 10, 1, 106511);
