INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 23214, 1, 11, "今日は、本当にみんなありがとう。\nあたしの誕生日のために、こんなに\n素敵なケーキを用意してくれるなんてね♪", 0, 23214063, 0, 10, 1, 102811);
