INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 23214, 1, 11, "お誕生日おめでとう、ママ・サレン♪\nいつも、私たちのために、\n一生懸命お仕事頑張って\nくれてるから……", 0, 23214068, 0, 10, 1, 102111);
