INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 23814, 1, 11, "どうもありがとう♪\nそれにしても素晴らしいケーキだね、\nボクのために用意してくれたの？", 0, 23814084, 0, 10, 1, 100811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 23814, "", 91, "", "", 23814085, "", "", "", 0);
