INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 23814, 1, 11, "はい♪　喜んでもらえるように、\nお店の人に頼んでしっかり\n見た目にもこだわってもらいました。", 0, 23814089, 0, 10, 1, 105511);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 23814, "", 91, "", "", 23814090, "", "", "", 0);
