INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 23814, 1, 11, "ちなみにご予算がかかったので、\nショーグンにもルピを出してもらい\nマシタ！　感謝の極みデス！", 0, 23814094, 0, 10, 1, 103011);
