INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 25314, 1, 11, "当然だな☆\nこのクリスティーナが全て段取りを\nつけたのだ、満足できないはずがない！", 0, 25314075, 0, 10, 1, 107111);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 25314, "", 91, "", "", 25314076, "", "", "", 0);
