INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 28414, 1, 11, "ふふん、マツリちゃんもまた一歩、\nワタシに近づいたということだ。\n良かったな、これからも\nビシバシ鍛えてやるから期待していろ♪", 0, 28414078, 0, 10, 1, 107111);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 28414, "", 91, "", "", 28414079, "", "", "", 0);
