INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 30314, 1, 11, "えっと、私の誕生日をお祝いしてくれて\nありがとう。こんなふうに、\n誰かにお祝いしてもらえるなんて\n思ってなかったわ。", 0, 30314065, 0, 10, 1, 106411);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 91, "", "", 30314066, "", "", "", 0);
