INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 3, "wac_birthday_talk_smile", "", 30314068, 0.2, 1, "", 105811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 21, "vo_wac_30314_001", "", 30314069, "", 0, 0, "vo_wac_30314");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 30314, 1, 11, "お祝いするに決まってますよ～！\nシェフィちゃんは【美食殿】の大切な\n仲間なんですから♪", 0, 30314070, 0, 10, 1, 105811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 91, "", "", 30314071, "", "", "", 0);
