INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 3, "wac_birthday_talk_sad", "", 30314073, 0.2, 1, "", 106411);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 21, "vo_wac_30314_002", "", 30314074, "", 0, 0, "vo_wac_30314");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 30314, 1, 11, "でも、たくさん迷惑をかけているし。\nこんなふうにお祝いをしてもらう\n資格なんて……私には……", 0, 30314075, 0, 10, 1, 106411);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 91, "", "", 30314076, "", "", "", 0);
