INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 21, "vo_wac_30314_003", "", 30314079, "", 0, 0, "vo_wac_30314");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 30314, 1, 11, "そうよね～、迷惑かけまくりよね～？\nお腹が空いたらすぐ泣くし、目についた\n物はなんでも口に入れちゃうし。", 0, 30314080, 0, 10, 1, 106011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 91, "", "", 30314081, "", "", "", 0);
