INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 21, "vo_wac_30314_004", "", 30314084, "", 0, 0, "vo_wac_30314");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 30314, 1, 11, "そ、それはまた別の話でしょう！？\n私が言いたいのは……！", 0, 30314085, 0, 10, 1, 106411);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 30314, "", 91, "", "", 30314086, "", "", "", 0);
