INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 31314, 1, 11, "お、おお、おめでとうございます！\n私のようなぼっちが、陽の者である\nハツネさんの誕生日をお祝いするのは、\n恐れ多い感じではあるんですが！", 0, 31314068, 0, 10, 1, 104011);
