INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 31714, 1, 11, "これが、お誕生日ケーキ……\nす、すごく、うれしいわ……！\nわたしなんかの、ために……\nありがとう……", 0, 31714058, 0, 10, 1, 118111);
