INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 21, "vo_wac_32114_000", "", 32114064, "", 0, 0, "vo_wac_32114");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32114, 1, 11, "えっとさー、その～……\n普段あんまりお仕事してないのに、\nこんな大げさにお祝いされると\n気まずいっていうか～……", 0, 32114065, 0, 10, 1, 102611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 91, "", "", 32114066, "", "", "", 0);
