INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 3, "wac_birthday_talk_smile", "", 32114068, 0.2, 1, "", 105211);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 21, "vo_wac_32114_001", "", 32114069, "", 0, 0, "vo_wac_32114");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32114, 1, 11, "今さら気にするくらいなら、\n普段からしっかりやればいいのに。\n……なんてお小言はさておき、\nお誕生日おめでとう、リンちゃん♪", 0, 32114070, 0, 10, 1, 105211);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 91, "", "", 32114071, "", "", "", 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 3, "wac_birthday_idle_smile", "", 32114072, 0.2, 1, "", 105211);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 3, "wac_birthday_talk_wish", "", 32114073, 0.2, 1, "", 103811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 21, "vo_wac_32114_002", "", 32114074, "", 0, 0, "vo_wac_32114");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32114, 1, 11, "変に遠慮しないでくださいね？\nみんな、リンちゃんのことを\nお祝いしたくて、張り切って\n準備したんですから。", 0, 32114075, 0, 10, 1, 103811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 91, "", "", 32114076, "", "", "", 0);
