INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 3, "wac_birthday_talk_smile", "", 32114078, 0.2, 1, "", 102611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 21, "vo_wac_32114_003", "", 32114079, "", 0, 0, "vo_wac_32114");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32114, 1, 11, "うぅ……そうだったんだね……\nここまでしてもらったんだから、\nあたしも心を入れ替えて、\n来年からはお仕事がんばるよ！", 0, 32114080, 0, 10, 1, 102611);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 91, "", "", 32114081, "", "", "", 0);
