INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 21, "vo_wac_32114_004", "", 32114084, "", 0, 0, "vo_wac_32114");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32114, 1, 11, "ほ、本当だべか！？\n苦労して誕生日パーティーを用意した\n甲斐があったべさ～……って、ん？\nちょっと待つべ、来年？", 0, 32114085, 0, 10, 1, 103311);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32114, "", 93, 1, "", 32114086, "", "", "", 7);
