INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32114, 1, 11, "そう、来年から～\nというわけで今年も一年、\nぐうたらライフで平常運転\nしていくんで、よろしく～", 0, 32114092, 0, 10, 1, 102611);
