INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32314, 1, 11, "誕生日のお祝い、ありがとね！\nアタシももう、立派なレディの\n仲間入りって感じかしら♪", 0, 32314058, 0, 10, 1, 105011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32314, "", 91, "", "", 32314059, "", "", "", 0);
