INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32314, "", 21, "vo_wac_32314_002", "", 32314067, "", 0, 0, "vo_wac_32314");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32314, 1, 11, "えっ！？\nそ、それは、その～……\n大人のレディ向けジュースとかないの？\n苦いのも、別にダメじゃないけど！", 0, 32314068, 0, 10, 1, 105011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32314, "", 91, "", "", 32314069, "", "", "", 0);
