INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 32314, 1, 11, "ふふっ、ちゃんとあるわよ♪\nこうやってオシャレなグラスに\nぶどうジュースを注げば……\nほら、大人っぽいでしょう？", 0, 32314073, 0, 10, 1, 101811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 32314, "", 91, "", "", 32314074, "", "", "", 0);
