INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 33214, 1, 11, "今日は、こんな素敵な誕生日ケーキを\n用意してくれてありがとう。\nその……すまない、なんだか\n照れくさくて、上手く話せないな。", 0, 33214058, 0, 10, 1, 100311);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 33214, "", 91, "", "", 33214059, "", "", "", 0);
