INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 33214, "", 21, "vo_wac_33214_001", "", 33214062, "", 0, 0, "vo_wac_33214");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 33214, 1, 11, "大丈夫だよ。\n今のレイちゃんの顔を見たら、\nすごく喜んでくれてるって\nちゃんと分かるから♪", 0, 33214063, 0, 10, 1, 100211);
