INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 33214, 1, 11, "顔を真っ赤にしてるレイさんなんて\nなかなか見られないからね～\nほらほら、騎士くんもしっかり\n目に焼き付けておきなよ♪", 0, 33214068, 0, 10, 1, 100111);
