INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 34314, 1, 11, "う～む。\n際限なくプリンを要求してくるのは、\nもう悪霊に片足を突っ込んで\nおらんかのう？", 0, 34314096, 0, 10, 1, 104411);
