INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 34414, 1, 11, "お返しって考えたらどうでしょう？\nほら、今回も騎士さんにケーキの\n用意とか手伝ってもらいましたし。\nアイドルらしいお礼になりませんか？", 0, 34414068, 0, 10, 1, 105411);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 34414, "", 91, "", "", 34414069, "", "", "", 0);
