INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 35514, 1, 11, "わーい！　ルゥのケーキですぅ～～♪\nルゥ、みんなにお祝いしてもらえるの\n楽しみにしてたですよ！", 0, 35514058, 0, 10, 1, 109311);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 35514, "", 91, "", "", 35514059, "", "", "", 0);
