INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 35514, 1, 11, "楽しみにしてもらえて良かった！\n今回はグレアと一緒に、\nルゥのために手作りしたからね！\n私が材料をぐるぐるかき混ぜて……", 0, 35514063, 0, 10, 1, 109211);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 35514, "", 91, "", "", 35514064, "", "", "", 0);
