INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 35514, 1, 11, "私がフルーツをもりつけたんだ。\nあと、この人の提案で\n味も甘めにしておいたからね。\nルゥが好きかなって……", 0, 35514068, 0, 10, 1, 109411);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 35514, "", 91, "", "", 35514069, "", "", "", 0);
