INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 36914, 1, 11, "ん？　何か特別な日だっただろうか？\n確かこの日がいいと言ったのは……\nキミだったか？", 0, 36914085, 0, 10, 1, 100311);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 36914, "", 91, "", "", 36914086, "", "", "", 0);
