INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 21, "vo_wac_37914_000", "", 37914057, "", 0, 0, "vo_wac_37914");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 37914, 1, 11, "おおっ、この蝋燭をぼくのために？\nなんと手の込んだ複雑な香りだ。\nその下には大層な土台まで……\nこれはバースデー土台というやつだな！", 0, 37914058, 0, 10, 1, 111011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 91, "", "", 37914059, "", "", "", 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 3, "wac_birthday_idle_wish", "", 37914060, 0.2, 1, "", 111011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 3, "wac_birthday_talk_normal", "", 37914061, 0.2, 1, "", 110811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 21, "vo_wac_37914_001", "", 37914062, "", 0, 0, "vo_wac_37914");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 37914, 1, 11, "一応うちらの手作り系なんすけど、\nパイセンどうせケーキ興味ないすよね。\n後うちらでテキトーに片付けとくんで\nもう帰っていいすよ。お疲れー", 0, 37914063, 0, 10, 1, 110811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 91, "", "", 37914064, "", "", "", 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 3, "wac_birthday_idle_normal", "", 37914065, 0.2, 1, "", 110811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 3, "wac_birthday_yuni_talk_anger", "", 37914066, 0.2, 1, "", 111011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 21, "vo_wac_37914_002", "", 37914067, "", 0, 0, "vo_wac_37914");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 37914, 1, 11, "馬鹿を言うんじゃあない後輩たち。\nこうも膳立てされて食わぬ腹があるか。\n君らの気持ち、しかと受け止めてやる。\n端的に換言すれば、ぼくをハブるな。", 0, 37914068, 0, 10, 1, 111011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 91, "", "", 37914069, "", "", "", 0);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 3, "wac_birthday_talk_normal", "", 37914070, 0.2, 1, "", 111011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 21, "vo_wac_37914_003", "", 37914071, "", 0, 0, "vo_wac_37914");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 37914, 1, 11, "ああいや、礼ぐらい言わせてくれ。\nかくも立派な蝋燭と土台を用意するのは\n骨が折れたろう。その厚意に感謝する。\nさあ誕生日を始めるぞ、ヒャッハー！", 0, 37914072, 0, 10, 1, 111011);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 37914, "", 93, 1, "", 37914073, "", "", "", 11);
