INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 38214, 1, 11, "マヒルさん、どうしました……？\nもしかして、誕生日ケーキに\n変なところでも……？", 0, 38214070, 0, 10, 1, 103811);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 38214, "", 91, "", "", 38214071, "", "", "", 0);
