INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 38214, 1, 11, "そうそう。\n難しい顔するより、\nみんなで楽しくおいしくケーキを\n食べましょう♪", 0, 38214085, 0, 10, 1, 105211);
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 38214, "", 91, "", "", 38214086, "", "", "", 0);
