INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 38614, 1, 11, "クスクス……安心してください。\n少なくともロウソクの数よりは、\nずっと若々しく見えていますわ……♪", 0, 38614100, 0, 10, 1, 102711);
