INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 39114, 1, 11, "いろんなことがあったわよね……\n飛空艇を沈め、学院を破壊し、\n何度も破産の危機を迎えながらも……", 0, 39114073, 0, 10, 1, 104811);
