INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 39114, 1, 11, "麦しゅわの助けも借りながら、\nみんなで協力して、\n全部乗り越えることができたもの！", 0, 39114078, 0, 10, 1, 103411);
