INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.5, 40314, 1, 11, "ネネカちゃんは、\n私の夢を叶えてくれた恩人ですもの。\nこれくらい、当然だわ♪\n彼も彼でお礼がしたかったみだいだし。", 0, 40314053, 0, 10, 1, 105211);
